S=[]
cover=Table([[P('ПЕРСОНАЛЬНЫЙ ПЛАН<br/>ПОДГОТОВКИ 3.0','T')],[P('13 июля 2026 — 28 февраля 2027<br/>Каждый день • точные паузы • месячные ориентиры','CW')]],colWidths=[182*mm],rowHeights=[62*mm,28*mm],style=[('BACKGROUND',(0,0),(-1,-1),GREEN),('VALIGN',(0,0),(-1,-1),'MIDDLE'),('ALIGN',(0,0),(-1,-1),'CENTER')])
S += [Spacer(1,20*mm),cover,Spacer(1,9*mm),tbl([['Профиль','Данные'],['Возраст / рост / масса','19 лет / 195 см / 75 кг'],['Рекорды','5 км 19:00; 3 км 11:00; 100 м 13,6; подтягивания 25; брусья 45; КСУ 9'],['Цели','5 км 17–18; 3 км <10:00; подтягивания 40; брусья 90; КСУ 20'],['Инвентарь','турник, брусья, гири 16 и 24 кг'],['Ограничения','боль и шаткость колена при беге; операция на глаз ориентировочно в августе']],[45*mm,137*mm]),Spacer(1,7*mm),note('КРИТИЧЕСКИ ВАЖНО','При шаткости колена бег, спринты, прыжки и тесты запрещены до ортопеда. После операции сроки возврата к висам, натуживанию, гирям и бегу назначает хирург. Календарь автоматически сдвигается вслед за реальной датой допуска.',RED),PageBreak()]
S += [P('1. Трезвая оценка целей','H1'),P('Силовые цели амбициозны, но возможны в верхнем сценарии при стабильном наборе массы, отсутствии длительной послеоперационной паузы и 90% выполненных занятий. 3 км быстрее 10 минут и 5 км 17–18 минут требуют здорового колена, системного бегового объёма и возвращения к бегу не позднее осени. Ни один план не может гарантировать эти цифры; этот документ максимизирует вероятность без тренировки через травму.'),tbl([['Показатель','Минимум','Реалистичный февраль','Максимум'],['5 км','18:15–18:40','17:35–18:00','17:00–17:30'],['3 км','10:15–10:30','9:50–10:05','9:35–9:49'],['100 м','13,0–13,3','12,7–13,0','12,4–12,7'],['Подтягивания','34–36','37–40','40–43'],['Брусья','75–82','85–90','90–96'],['КСУ','16–18','19–20','20–22'],['Рывок 24 кг / 10 мин','55–70','75–90','90–110']],[40*mm,45*mm,52*mm,45*mm]),Spacer(1,7*mm),note('КАК УСКОРЯЕМ','3 недели наращивания + 1 разгрузочная. Прибавка недельного объёма 5–8% только при RIR ≥2, хорошем сне и отсутствии реакции через 24 часа. Каждые 4 недели — контроль 1–2 показателей, затем двухнедельный акцент на самом отстающем.',GREEN),P('Единые правила','H2'),tbl([['Параметр','Правило'],['RIR 2','Закончить подход, когда осталось примерно 2 чистых повтора. Не превращать рабочие дни в тесты.'],['Между упражнениями','После последнего подхода основного упражнения отдыхать 3 минуты; перед следующим блоком — 2 минуты.'],['Боль','0–2/10 без ухудшения наутро допустимо только после врача; 3+/10, отёк или шаткость — стоп.'],['Разгрузка','Каждая 4-я неделя: подходы −35–45%, интенсивность сохранить умеренной, максимумов нет.'],['Питание','Белок 120–150 г/сутки; профицит 250–350 ккал; прирост массы 0,15–0,30 кг/неделю.'],['Сон','8–9 часов. При сне <6,5 ч два дня подряд объём текущей тренировки −30%.']],[42*mm,140*mm]),PageBreak()]
S += [P('2. Промежуточные результаты по месяцам','H1'),P('Звёздочка означает: показатель проверяется только при медицинском допуске, без боли и шаткости. Если допуска нет, записать «не тестировать», а не форсировать календарную цифру.'),tbl(milestones,[25*mm,18*mm,21*mm,21*mm,18*mm,18*mm,18*mm,15*mm,28*mm],font='S'),Spacer(1,6*mm),note('ГИРЯ 24 КГ','Исходного теста нет. Сначала 4–6 недель техники. Первый 10-минутный контроль — только когда 5×5 на каждую руку выполняются чисто, без удара по предплечью и без натуживания, запрещённого хирургом.'),PageBreak()]
S += [P('3. Фазы подготовки','H1')]
S.append(tbl([['Фаза','Период и задача']]+[[a,b] for a,b in phases],[45*mm,137*mm]))
S += [Spacer(1,7*mm),P('Критерий допуска к бегу','H2'),P('Нужны: заключение ортопеда; отсутствие подкашивания; ходьба 45 минут без боли; 10 контролируемых приседаний на одной ноге до комфортной глубины; 20 подъёмов на носок; 10 лёгких прыжков на месте без боли и реакции через 24 часа — только если врач разрешил. Затем 2 недели walk-run. Это не самостоятельная диагностика.'),PageBreak()]

# календарь: одна неделя на 2 страницы, каждый день полностью расписан
start=date(2026,7,13); end=date(2027,2,28); d=start; week=1
loads=[.78,.9,1.0,.62]
ru=['ПОНЕДЕЛЬНИК','ВТОРНИК','СРЕДА','ЧЕТВЕРГ','ПЯТНИЦА','СУББОТА','ВОСКРЕСЕНЬЕ']
while d<=end:
 p=phase_for(d); load=loads[(week-1)%4]; a,b=phases[p]
 S += [P(f'Неделя {week} • {d:%d.%m.%Y}–{min(d+timedelta(days=6),end):%d.%m.%Y}','H1'),note('ФАЗА',f'{a}. {b} Нагрузка недели: {int(load*100)}% базового объёма. Критерий перехода: техника стабильна, RIR соблюдён, на следующее утро нет ухудшения.',GREEN)]
 for wd in range(7):
  day=d+timedelta(days=wd)
  if day>end: break
  title,text,duration=plan_day(p,wd,week,load)
  card=Table([[P(f'{ru[wd]} • {day:%d.%m} • {title}','CB')],[P(text,'S')],[P(f'<b>Общая длительность:</b> {duration}. Между упражнениями, если отдельно не указано: 2–3 мин.','S')]],colWidths=[182*mm],style=[('BACKGROUND',(0,0),(-1,0),LIME),('BOX',(0,0),(-1,-1),.5,LINE),('LEFTPADDING',(0,0),(-1,-1),7),('RIGHTPADDING',(0,0),(-1,-1),7),('TOPPADDING',(0,0),(-1,-1),5),('BOTTOMPADDING',(0,0),(-1,-1),5)])
  S += [KeepTogether(card),Spacer(1,3*mm)]
 S += [P('Итог недели: выполнено ___/7; средний сон ___ ч; масса ___ кг; боль колена утром ___/10; усталость ___/10. Решение: повысить / повторить / снизить объём.','S'),PageBreak()]
 d += timedelta(days=7); week += 1

S += [P('4. Контроль и корректировка','H1'),tbl([['Статус','Критерии','Действие'],['ЗЕЛЁНЫЙ','Все тренировки, RIR ≥2, сон ≥7 ч, нет ухудшения','Следующая неделя по плану; объём + не более 5–8%.'],['ЖЁЛТЫЙ','Недосып, усталость 7/10, техника падает, лёгкая реакция','Повторить неделю или срезать подходы на 30%.'],['КРАСНЫЙ','Боль 3+/10, отёк, подкашивание, ухудшение зрения/сильная головная боль','Прекратить провоцирующую нагрузку и обратиться к врачу.']],[28*mm,77*mm,77*mm]),Spacer(1,6*mm),P('Порядок месячного контроля','H2'),P('День 1: максимум подтягиваний после 48 часов без тяги. День 3: максимум брусьев. День 5: один профильный тест — КСУ или гиря. Беговой тест — в отдельную неделю, только после допуска. Между тестами не выполнять отказную работу.'),P('Чек-лист перед каждой тренировкой','H2'),tbl([['Проверка','Да / нет'],['Спал не менее 7 часов',''],['Нет новых симптомов глаза и ограничений хирурга',''],['Колено не отекает и не подкашивается',''],['Понимаю целевой RIR и объём дня',''],['Вода и приём пищи запланированы',''],['Записал результат после занятия','']],[145*mm,37*mm]),Spacer(1,6*mm),note('ФИНАЛЬНОЕ ПРАВИЛО','Цель достигается не максимальной нагрузкой каждый день, а максимальным числом качественных недель подряд. При конфликте календаря и медицинского допуска всегда побеждает допуск.',GREEN)]
doc.build(S,onFirstPage=footer,onLaterPages=footer)
print(OUT)
